196	  /// Add container concept to the given ContainerType
197	  /// http://www.sgi.com/tech/stl/Container.html
198	  template<typename ContainerType>
199	  void container_type(const std::string & /*type*/, Module &m) {
200	    m.add(fun([](const ContainerType *a) { return a->size(); }), "size");
201	    m.add(fun([](const ContainerType *a) { return a->empty(); }), "empty");
202	    m.add(fun([](ContainerType *a) { a->clear(); }), "clear");
203	  }
204	
205	  /// Add default constructable concept to the given Type
206	  /// http://www.sgi.com/tech/stl/DefaultConstructible.html
207	  template<typename Type>
208	  void default_constructible_type(const std::string &type, Module &m) {
209	    m.add(constructor<Type()>(), type);
210	  }
211	
212	  /// Add sequence concept to the given ContainerType
213	  /// http://www.sgi.com/tech/stl/Sequence.html
214	  template<typename ContainerType>
215	  void sequence_type(const std::string & /*type*/, Module &m) {
216	    m.add(fun(&detail::insert_at<ContainerType>), []() -> std::string {
217	      if (typeid(typename ContainerType::value_type) == typeid(Boxed_Value)) {
218	        return "insert_ref_at";
219	      } else {
220	        return "insert_at";
221	      }
222	    }());
223	
224	    m.add(fun(&detail::erase_at<ContainerType>), "erase_at");
225	  }
226	
227	  /// Add back insertion sequence concept to the given ContainerType
228	  /// http://www.sgi.com/tech/stl/BackInsertionSequence.html
229	  template<typename ContainerType>
230	  void back_insertion_sequence_type(const std::string &type, Module &m) {
231	    m.add(fun([](ContainerType &container) -> decltype(auto) {
232	            if (container.empty()) {
233	              throw std::range_error("Container empty");
234	            } else {
235	              return (container.back());
236	            }
237	          }),
238	          "back");
239	    m.add(fun([](const ContainerType &container) -> decltype(auto) {
240	            if (container.empty()) {
241	              throw std::range_error("Container empty");
242	            } else {
243	              return (container.back());
244	            }
245	          }),
246	          "back");
247	
248	    using push_back = void (ContainerType::*)(const typename ContainerType::value_type &);
249	    m.add(fun(static_cast<push_back>(&ContainerType::push_back)), [&]() -> std::string {
250	      if (typeid(typename ContainerType::value_type) == typeid(Boxed_Value)) {
251	        m.eval("# Pushes the second value onto the container while making a clone of the value\n"
252	               "def push_back("
253	               + type
254	               + " container, x)\n"
255	                 "{ \n"
256	                 "  if (x.is_var_return_value()) {\n"
257	                 "    x.reset_var_return_value() \n"
258	                 "    container.push_back_ref(x) \n"
259	                 "  } else { \n"
260	                 "    container.push_back_ref(clone(x)); \n"
261	                 "  }\n"
262	                 "} \n");
263	
264	        return "push_back_ref";
265	      } else {
266	        return "push_back";
267	      }
268	    }());
269	
270	    m.add(fun(&ContainerType::pop_back), "pop_back");
271	  }
272	
273	  /// Front insertion sequence
274	  /// http://www.sgi.com/tech/stl/FrontInsertionSequence.html
275	  template<typename ContainerType>
276	  void front_insertion_sequence_type(const std::string &type, Module &m) {
277	    using push_ptr = void (ContainerType::*)(typename ContainerType::const_reference);
278	    using pop_ptr = void (ContainerType::*)();
279	
280	    m.add(fun([](ContainerType &container) -> decltype(auto) {
281	            if (container.empty()) {
282	              throw std::range_error("Container empty");
283	            } else {
284	              return (container.front());
285	            }
286	          }),
287	          "front");
288	
289	    m.add(fun([](const ContainerType &container) -> decltype(auto) {
290	            if (container.empty()) {
291	              throw std::range_error("Container empty");
292	            } else {
293	              return (container.front());
294	            }
295	          }),
296	          "front");
297	
298	    m.add(fun(static_cast<push_ptr>(&ContainerType::push_front)), [&]() -> std::string {
299	      if (typeid(typename ContainerType::value_type) == typeid(Boxed_Value)) {
300	        m.eval("# Pushes the second value onto the front of container while making a clone of the value\n"
301	               "def push_front("
302	               + type
303	               + " container, x)\n"
304	                 "{ \n"
305	                 "  if (x.is_var_return_value()) {\n"
306	                 "    x.reset_var_return_value() \n"
307	                 "    container.push_front_ref(x) \n"
308	                 "  } else { \n"
309	                 "    container.push_front_ref(clone(x)); \n"
310	                 "  }\n"
311	                 "} \n");
312	        return "push_front_ref";
313	      } else {
314	        return "push_front";
315	      }
316	    }());
317	
318	    m.add(fun(static_cast<pop_ptr>(&ContainerType::pop_front)), "pop_front");
319	  }
320	
321	  /// bootstrap a given PairType
322	  /// http://www.sgi.com/tech/stl/pair.html
323	  template<typename PairType>
324	  void pair_type(const std::string &type, Module &m) {
325	    m.add(user_type<PairType>(), type);
326	
327	    m.add(fun(&PairType::first), "first");
328	    m.add(fun(&PairType::second), "second");
329	
330	    basic_constructors<PairType>(type, m);
331	    m.add(constructor<PairType(const typename PairType::first_type &, const typename PairType::second_type &)>(), type);
332	  }
333	
334	  /// Add pair associative container concept to the given ContainerType
335	  /// http://www.sgi.com/tech/stl/PairAssociativeContainer.html
336	
337	  template<typename ContainerType>
338	  void pair_associative_container_type(const std::string &type, Module &m) {
339	    pair_type<typename ContainerType::value_type>(type + "_Pair", m);
340	  }
341	
342	  /// Add unique associative container concept to the given ContainerType
343	  /// http://www.sgi.com/tech/stl/UniqueAssociativeContainer.html
344	  template<typename ContainerType>
345	  void unique_associative_container_type(const std::string & /*type*/, Module &m) {
346	    m.add(fun(detail::count<ContainerType>), "count");
347	
348	    using erase_ptr = size_t (ContainerType::*)(const typename ContainerType::key_type &);
349	
350	    m.add(fun(static_cast<erase_ptr>(&ContainerType::erase)), "erase");
351	
352	    m.add(fun(&detail::insert<ContainerType>), "insert");
353	
354	    m.add(fun(&detail::insert_ref<ContainerType>), []() -> std::string {
355	      if (typeid(typename ContainerType::mapped_type) == typeid(Boxed_Value)) {
356	        return "insert_ref";
357	      } else {
358	        return "insert";
359	      }
360	    }());
361	  }
362	
363	  /// Add a MapType container
364	  /// http://www.sgi.com/tech/stl/Map.html
365	  template<typename MapType>
366	  void map_type(const std::string &type, Module &m) {
367	    m.add(user_type<MapType>(), type);
368	
369	    using elem_access = typename MapType::mapped_type &(MapType::*)(const typename MapType::key_type &);
370	    using const_elem_access = const typename MapType::mapped_type &(MapType::*)(const typename MapType::key_type &) const;
371	
372	    m.add(fun(static_cast<elem_access>(&MapType::operator[])), "[]");
373	
374	    m.add(fun(static_cast<elem_access>(&MapType::at)), "at");
375	    m.add(fun(static_cast<const_elem_access>(&MapType::at)), "at");
376	
377	    if (typeid(MapType) == typeid(std::map<std::string, Boxed_Value>)) {
378	      m.eval(R"(
379	                    def Map::`==`(Map rhs) {
380	                       if ( rhs.size() != this.size() ) {
381	                         return false;
382	                       } else {
383	                         auto r1 = range(this);
384	                         auto r2 = range(rhs);
385	                         while (!r1.empty())
386	                         {
387	                           if (!eq(r1.front().first, r2.front().first) || !eq(r1.front().second, r2.front().second))
388	                           {
389	                             return false;
390	                           }
391	                           r1.pop_front();
392	                           r2.pop_front();
393	                         }
394	                         true;
395	                       }
396	                   } )");
397	    }
398	
399	    container_type<MapType>(type, m);
400	    default_constructible_type<MapType>(type, m);
401	    assignable_type<MapType>(type, m);
402	    unique_associative_container_type<MapType>(type, m);
403	    pair_associative_container_type<MapType>(type, m);
404	    input_range_type<MapType>(type, m);
405	  }
406	
407	  /// http://www.sgi.com/tech/stl/List.html
408	  template<typename ListType>
409	  void list_type(const std::string &type, Module &m) {
410	    m.add(user_type<ListType>(), type);
411	
412	    front_insertion_sequence_type<ListType>(type, m);
413	    back_insertion_sequence_type<ListType>(type, m);
414	    sequence_type<ListType>(type, m);
415	    resizable_type<ListType>(type, m);
416	    container_type<ListType>(type, m);
417	    default_constructible_type<ListType>(type, m);
418	    assignable_type<ListType>(type, m);
419	    input_range_type<ListType>(type, m);
420	  }
421	
422	  /// Create a vector type with associated concepts
423	  /// http://www.sgi.com/tech/stl/Vector.html
424	  template<typename VectorType>
425	  void vector_type(const std::string &type, Module &m) {
426	    m.add(user_type<VectorType>(), type);
427	
428	    m.add(fun([](VectorType &container) -> decltype(auto) {
429	            if (container.empty()) {
430	              throw std::range_error("Container empty");
431	            } else {
432	              return (container.front());
433	            }
434	          }),
435	          "front");
436	
437	    m.add(fun([](const VectorType &container) -> decltype(auto) {
438	            if (container.empty()) {
439	              throw std::range_error("Container empty");
440	            } else {
441	              return (container.front());
442	            }
443	          }),
444	          "front");
445	
446	    back_insertion_sequence_type<VectorType>(type, m);
447	    sequence_type<VectorType>(type, m);
448	    random_access_container_type<VectorType>(type, m);
449	    resizable_type<VectorType>(type, m);
450	    reservable_type<VectorType>(type, m);
451	    container_type<VectorType>(type, m);
452	    default_constructible_type<VectorType>(type, m);
453	    assignable_type<VectorType>(type, m);
454	    input_range_type<VectorType>(type, m);
455	
456	    if (typeid(VectorType) == typeid(std::vector<Boxed_Value>)) {
457	      m.eval(R"(
458	                    def Vector::`==`(Vector rhs) {
459	                       if ( rhs.size() != this.size() ) {
460	                         return false;
461	                       } else {
462	                         auto r1 = range(this);
463	                         auto r2 = range(rhs);
464	                         while (!r1.empty())
465	                         {
466	                           if (!eq(r1.front(), r2.front()))
467	                           {
468	                             return false;
469	                           }
470	                           r1.pop_front();
471	                           r2.pop_front();
472	                         }
473	                         true;
474	                       }
475	                   } )");
476	    }
477	  }
478	
479	  /// Add a String container
480	  /// http://www.sgi.com/tech/stl/basic_string.html
481	  template<typename String>
482	  void string_type(const std::string &type, Module &m) {
483	    m.add(user_type<String>(), type);
484	    operators::addition<String>(m);
485	    operators::assign_sum<String>(m);
486	    opers_comparison<String>(m);
487	    random_access_container_type<String>(type, m);
488	    sequence_type<String>(type, m);
489	    default_constructible_type<String>(type, m);
490	    // container_type<String>(type, m);
491	    assignable_type<String>(type, m);
492	    input_range_type<String>(type, m);
493	
494	    // Special case: add push_back to string (which doesn't support other back_insertion operations
495	    m.add(fun(&String::push_back), []() -> std::string {
496	      if (typeid(typename String::value_type) == typeid(Boxed_Value)) {
497	        return "push_back_ref";
498	      } else {
499	        return "push_back";
500	      }
501	    }());
502	
503	    m.add(fun([](const String *s, const String &f, size_t pos) { return s->find(f, pos); }), "find");
504	    m.add(fun([](const String *s, const String &f, size_t pos) { return s->rfind(f, pos); }), "rfind");
505	    m.add(fun([](const String *s, const String &f, size_t pos) { return s->find_first_of(f, pos); }), "find_first_of");
506	    m.add(fun([](const String *s, const String &f, size_t pos) { return s->find_last_of(f, pos); }), "find_last_of");
507	    m.add(fun([](const String *s, const String &f, size_t pos) { return s->find_last_not_of(f, pos); }), "find_last_not_of");
508	    m.add(fun([](const String *s, const String &f, size_t pos) { return s->find_first_not_of(f, pos); }), "find_first_not_of");
509	
510	    m.add(fun([](String *s, typename String::value_type c) -> decltype(auto) { return (*s += c); }), "+=");
511	
512	    m.add(fun([](String *s) { s->clear(); }), "clear");
513	    m.add(fun([](const String *s) { return s->empty(); }), "empty");
514	    m.add(fun([](const String *s) { return s->size(); }), "size");
515	
516	    m.add(fun([](const String *s) { return s->c_str(); }), "c_str");
517	    m.add(fun([](const String *s) { return s->data(); }), "data");
518	    m.add(fun([](const String *s, size_t pos, size_t len) { return s->substr(pos, len); }), "substr");
519	  }
520	
521	  /// Add a MapType container
522	  /// http://www.sgi.com/tech/stl/Map.html
